import functools
import collections
import threading
import typing

T = typing.TypeVar("T")

class ThreadSafeLRUCache:
    def __init__(self, maxsize: int = 128):
        self.cache = collections.OrderedDict()
        self.maxsize = maxsize
        self.lock = threading.Lock()

    def __call__(self, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            with self.lock:
                if args not in self.cache or len(self.cache) > self.maxsize:
                    self.cache.popitem(last=False)
                result = func(*args)
                self.cache[args] = result
                return result
        return wrapper

class MemoizedLRUMetaclass(type):
    _cache_lock = threading.Lock()

    def __init__(cls, name, bases, attrs):
        super().__init__(name, bases, attrs)

        # Type checking
        if cls is not MemoizedLRUMetaclass:
            for base in bases:
                if issubclass(base, typing.Generic):
                    cls.__orig_bases__ = (base,) + cls.__orig_bases__
                    break

            if not hasattr(cls, "__parameters__"):
                cls.__parameters__ = {}
                for base in cls.__orig_bases__:
                    if hasattr(base, "__parameters__"):
                        cls.__parameters__.update(base.__parameters__)

