        return super().__new__(mcs, name, bases, attrs)

class MemoizedLRUClass(metaclass=MemoizedLRUMetaclass):
    def __init__(self, a: T, b: T):
        self.a = a
        self.b = b

    def add(self, x: T, y: T) -> T:
        return self.a + x + y + self.b

# Example usage
class_instance = MemoizedLRUClass(1, 2)
