            with cls._memoize_lock:
                return func(*args, **kwargs)

        wrapper._memoize = True
        return wrapper

# Usage example:

class MyClass(metaclass=MemoizeMeta):
    @MemoizeMeta.memoize
    def fibonacci(self, n):
        if n <= 1:
            return n
        else:
            return self.fibonacci(n - 1) + self.fibonacci(n - 2)

obj = MyClass()
