from functools import lru_cache, wraps
from threading import Lock
from typing import Any, Callable, TypeVar, get_type_hints
import time

T = TypeVar('T')

class MemoizedMeta(type):
    _cache = {}
    _lock = Lock()

    def __new__(mcs, name, bases, dct):
        original_init = dct.get('__init__')

        def __init__(self, *args, **kwargs):
            if original_init is not None:
                original_init(self, *args, **kwargs)
            self._instance_cache = {}
            self._instance_lock = Lock()

        dct['__init__'] = __init__

        for attr_name, attr_value in dct.items():
            if callable(attr_value):
                dct[attr_name] = mcs.memoized_method(attr_value)

        def __init_subclass__(cls, **kwargs):
            super().__init_subclass__(**kwargs)
            cls._check_type_hints()

        dct['__init_subclass__'] = __init_subclass__

        return super().__new__(mcs, name, bases, dct)

    @staticmethod
    def memoized_method(func: Callable) -> Callable:
        hints = get_type_hints(func)

        @wraps(func)
        def wrapper(self, *args, **kwargs):
            cache_key = (func.__qualname__, args, frozenset(kwargs.items()))

            with self._instance_lock:
                if cache_key in self._instance_cache:
                    return self._instance_cache[cache_key]

                result = func(self, *args, **kwargs)
                self._instance_cache[cache_key] = result
                return result

        return wrapper

    @classmethod
    def _check_type_hints(cls):
        for name, method in cls.__dict__.items():
            if callable(method):
                hints = get_type_hints(method)
                if hints:
                    print(f"Type hints for {name}: {hints}")

class MemoizedClass(metaclass=MemoizedMeta):
    def __init__(self):
        pass

    @staticmethod
    def expensive_computation(x: int) -> int:
        time.sleep(2)  # Simulate an expensive computation
        return x * x

    @staticmethod
    def another_method(y: str) -> str:
        time.sleep(1)  # Simulate another expensive computation
        return y * 2

# Example usage
if __name__ == "__main__":
    obj = MemoizedClass()
    print(obj.expensive_computation(10))  # This will take time
    print(obj.expensive_computation(10))  # This will be fast due to memoization
    print(obj.another_method("hello"))  # This will take time
    print(obj.another_method("hello"))  # This will be fast due to memoization
```

### Explanation:
1. **Metaclass (`MemoizedMeta`)**: 
   - The metaclass `MemoizedMeta` is responsible for adding memoization to methods of any class that uses it.
   - It overrides the `__new__` method to wrap instance methods with memoization logic.
   - It uses `__init_subclass__` to perform type checking on the methods.

2. **Memoization**:
   - The `memoized_method` decorator is applied to each method in the class. It caches the results of method calls based on their arguments.

3. **Thread Safety**:
   - A lock (`_instance_lock`) is used to ensure that memoization is thread-safe.

4. **Type Checking**:
   - The `__init_subclass__` method checks and prints type hints for all methods in the subclass.

This setup ensures that methods are memoized with LRU eviction (via the dictionary which naturally implements LRU when combined with method re-invocation order), are thread-safe, and have their type hints checked at compile time.

