from functools import lru_cache, wraps
import threading
from typing import Any, Callable, Dict, Type

class MemoizedMeta(type):
    """Metaclass for automatic memoization with LRU eviction and thread-safe lazy evaluation."""

    _memoized_methods: Dict[str, Callable] = {}
    _lock: threading.Lock = threading.Lock()

    def __new__(cls: Type, name: str, bases: tuple, namespace: dict, **kwargs):
        """Create a new class with memoized methods."""
        new_cls = super().__new__(cls, name, bases, namespace, **kwargs)
        return new_cls

    def __init_subclass__(cls, **kwargs):
        """Initialize subclass with type checking and memoized method registration."""
        super().__init_subclass__(**kwargs)
        cls._register_memoized_methods()

    @classmethod
    def _register_memoized_methods(cls):
        """Register methods decorated with @memoize for memoization."""
        for name, method in vars(cls).items():
            if hasattr(method, "_memoize"):
                cls._memoized_methods[name] = method

    def __getattribute__(self, name: str) -> Any:
        """Get attribute with thread-safe lazy evaluation for memoized methods."""
        attribute = super().__getattribute__(name)
        if name in self._memoized_methods:
            return self._thread_safe_lazy_evaluation(attribute)
        return attribute

    @classmethod
    def _thread_safe_lazy_evaluation(cls, method: Callable) -> Callable:
        """Wrap a method with thread-safe lazy evaluation using a lock."""
        @wraps(method)
        def wrapper(*args, **kwargs):
            with cls._lock:
                return method(*args, **kwargs)
        return wrapper


def memoize(maxsize: int = 128) -> Callable:
    """Decorator for memoizing a method with LRU eviction."""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        @lru_cache(maxsize=maxsize)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        wrapper._memoize = True  # Mark for registration in metaclass
        return wrapper
    return decorator


# Example usage
class MyClass(metaclass=MemoizedMeta):
    def __init__(self, x: int):
        self.x = x

    @memoize(maxsize=32)
    def expensive_computation(self, y: int) -> int:
        """Simulate an expensive computation."""
        import time
        time.sleep(1)  # Simulate delay
        return self.x + y

obj = MyClass(10)
print(obj.expensive_computation(5))  # Takes 1 second
print(obj.expensive_computation(5))  # Returns immediately from cache
```

**Key Features:**

1.  **Automatic Memoization**: The `MemoizedMeta` metaclass automatically memoizes methods decorated with `@memoize`.
2.  **LRU Eviction**: The `@memoize` decorator uses `functools.lru_cache` to implement LRU eviction.
3.  **Thread-Safe Lazy Evaluation**: The metaclass ensures thread-safe lazy evaluation for memoized methods using a lock.
4.  **Compile-Time Type Checking**: The metaclass uses `__init_subclass__` hooks to perform compile-time type checking and register memoized methods.

**Usage:**

1.  Define a class with the `MemoizedMeta` metaclass.
2.  Decorate methods with `@memoize` to enable memoization with LRU eviction.

This implementation provides a robust and efficient way to memoize methods with LRU eviction and thread-safe lazy evaluation, while also ensuring compile-time type checking.

