from functools import wraps
import threading
from collections import OrderedDict

class LRuCache:
    def __init__(self, maxsize=128):
        self.maxsize = maxsize
        selfcache = OrderedDict()

    def __getitem__(self, key):
        try:
            value = self.cache[key]
            self.cache.move_to_end(key)
            return value
        except KeyError:
            raise KeyError(key)

    def __setitem__(self, key, value):
        try:
            self.cache.pop(key)
        except KeyError:
            if len(self.cache) >= self.maxsize:
                self.cache.popitem(last=False)
        self.cache[key] = value

class LRULazyMeta(type):
    def __init__(cls, name, bases, class_dict):
        super().__init__(name, bases, class_dict)
        cls.cache = LRuCache()
        cls.cache_lock = threading.Lock()

    def wrapper(func):
        @wraps(func)
        def memoized(*args, **kwargs):
            key = (func, args, frozenset(kwargs.items()))
            with cls.cache_lock:
                if key not in cls.cache:
                    cls.cache[key] = func(*args, **kwargs)
                return cls.cache[key]
        return memoized

    def __new__(cls, name, bases, class_dict):
        for attr_name, attr_value in class_dict.items():
            if callable(attr_value):
                class_dict[attr_name] = cls.wrapper(attr_value)
        return super().__new__(cls, name, bases, class_dict)

@LRULazyMeta
class MyLazilyEvaluatedLRUClass:
    def __init_subclass__(cls, *args, **kwargs):
        super().__init_subclass__(*args, **kwargs)

        # Example type checking. Here we ensure each method has a docstring.
        for attr_name, attr_value in cls.__dict__.items():
