import functools
import threading
import typing
from typing import Any, Callable, Dict, Type, TypeVar, Union, Optional, Tuple
from collections import OrderedDict
import inspect

T = TypeVar('T')
R = TypeVar('R')

class TypeChecker:
    """Helper class for type checking at compile time"""

    @staticmethod
    def check_types(cls: Type[T], method_name: str, args: Tuple[Any, ...], kwargs: Dict[str, Any]) -> bool:
        """Check if method arguments match the type annotations"""
        try:
            method = getattr(cls, method_name)
            sig = inspect.signature(method)

            # Bind arguments to parameters
            bound_args = sig.bind(*args, **kwargs)
            bound_args.apply_defaults()

            # Check each parameter
            for param_name, param_value in bound_args.arguments.items():
                param_annotation = sig.parameters[param_name].annotation
                if param_annotation is not inspect.Parameter.empty:
                    if not isinstance(param_value, param_annotation):
                        if typing.get_origin(param_annotation) is Union:
                            # Handle Union types
                            valid = any(isinstance(param_value, t) for t in typing.get_args(param_annotation))
                            if not valid:
                                return False
                        else:
                            return False

            # Check return annotation if available
            return_annotation = sig.return_annotation
            if return_annotation is not inspect.Signature.empty:
                return True  # We can't check return type at call time

            return True
        except (TypeError, ValueError):
            return False

class MemoizedLRU:
    """Thread-safe LRU cache with customizable max size"""

    def __init__(self, maxsize: int = 128):
        self.maxsize = maxsize
        self.cache: OrderedDict = OrderedDict()
        self.lock = threading.RLock()
        self.hits = 0
        self.misses = 0

    def __call__(self, func: Callable[..., R]) -> Callable[..., R]:
        @functools.wraps(func)
        def wrapped(*args, **kwargs):
            key = (args, frozenset(kwargs.items())) if kwargs else args

            with self.lock:
                try:
                    value = self.cache.pop(key)
                    self.hits += 1
                except KeyError:
                    self.misses += 1
                    value = func(*args, **kwargs)
                    if self.maxsize is not None and len(self.cache) >= self.maxsize:
                        self.cache.popitem(last=False)
                    self.cache[key] = value

            return value

        def cache_info() -> Dict[str, int]:
            with self.lock:
                return {
                    'hits': self.hits,
                    'misses': self.misses,
                    'maxsize': self.maxsize,
                    'currsize': len(self.cache)
                }

        wrapped.cache_info = cache_info
        return wrapped

class CachedMethodDescriptor:
    """Descriptor for cached methods with lazy evaluation"""

    def __init__(self, name: str, func: Callable[..., R], maxsize: int = 128):
        self.name = name
        self.func = func
        self.cache = MemoizedLRU(maxsize)
        self.cached_func = self.cache(func)

    def __get__(self, obj: Optional[Any], objtype: Optional[Type[T]] = None) -> Callable[..., R]:
        return functools.partial(self.cached_func, obj)

    def __set__(self, obj: Any, value: Callable[..., R]) -> None:
        raise AttributeError(f"Cannot override {self.name} method")

class ThreadSafeLazyProperty:
    """Thread-safe lazy property descriptor"""

    def __init__(self, func: Callable[[Any], R]):
        self.func = func
        self.lock = threading.Lock()
        self.__doc__ = func.__doc__
        self.attr_name = None

    def __set_name__(self, owner: Type[T], name: str) -> None:
        self.attr_name = f'_{name}'

    def __get__(self, obj: Optional[Any], objtype: Optional[Type[T]] = None) -> R:
        if obj is None:
            return self

        with self.lock:
            try:
                value = getattr(obj, self.attr_name)
            except AttributeError:
                value = self.func(obj)
                setattr(obj, self.attr_name, value)

            return value

