import functools
import threading
from typing import TypeVar, Generic, Type, Any

T = TypeVar('T')

class _MemoizedMeta(type):
    def __init_subclass__(cls, **kwargs):
        for name, func in vars(cls).items():
            if callable(func):
                setattr(cls, name, _memoize(func))

def _memoize(func):
    cache = {}
    lock = threading.Lock()

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        key = (args, frozenset(kwargs.items()))
        with lock:
            if key in cache:
                return cache[key]
            result = func(*args, **kwargs)
            cache[key] = result
            if len(cache) > 100:  # LRU eviction
                cache.pop(next(iter(cache)))
            return result

    return wrapper

class Memoized(metaclass=_MemoizedMeta):
    pass

class MemoizedClass(Memoized):
    def expensive_computation(self, x: int, y: str) -> str:
        # simulate an expensive computation
        import time
        time.sleep(2)
        return f"Result: {x} + {y}"

# Example usage
obj = MemoizedClass()
print(obj.expensive_computation(1, "hello"))  # takes 2 seconds
print(obj.expensive_computation(1, "hello"))  # returns immediately from cache
